const body = $json.body;
const action = body.action || 'chat';
const rawId = body.sessionId || ('session_' + Date.now());
const sessionId = rawId.replace(/-/g, '_');

return [{
  json: {
    action,
    sessionId,
    prompt: body.prompt || '',
    history: body.history || [],
    fileData: body.fileData || null, // Le Base64
    fileName: body.fileName || '',
    fileType: body.fileType || ''
  }
}];

const stdout = $input.first().json.stdout || '';

if (!stdout || stdout.trim() === '' || stdout.includes('NO_FILES')) {
  return [{ json: { action: 'listSessions', sessions: [] } }];
}

const sessions = [];
const lines = stdout.split('\n');

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed || !trimmed.includes('.json')) continue;

  const parts = trimmed.split(/\s+/);
  if (parts.length < 3) continue;

  const isoDate  = parts[0]; // 2026-03-20T17:49
  const msgCount = parseInt(parts[1], 10) || 0;
  const fileName = parts[parts.length - 1].split('/').pop();

  if (!fileName.startsWith('session_') || !fileName.endsWith('.json')) continue;

  // Formate la date en DD/MM/YYYY HH:MM
  const [datePart, timePart] = isoDate.split('T');
  const [y, m, d] = (datePart || '').split('-');
  const displayDate = (d && m && y) ? `${d}/${m}/${y} ${timePart || ''}` : isoDate;

  const id = fileName.replace('.json', '');
  const exchanges = Math.floor(msgCount / 2);
  const title = `${displayDate} — ${exchanges} échange${exchanges > 1 ? 's' : ''}`;

  sessions.push({
    id,
    title,
    lastModified: isoDate,
    displayDate,
    messageCount: msgCount
  });
}

// ls -t a déjà trié, mais on re-trie par sécurité
sessions.sort((a, b) => new Date(b.lastModified) - new Date(a.lastModified));

return [{ json: { action: 'listSessions', sessions } }];

const sessionId = $json.sessionId;
const prompt = $json.prompt;
let history = $json.history || [];

if (typeof history === 'string') {
  try { history = JSON.parse(history); } catch (e) { history = []; }
}

let historyContext = '';
if (Array.isArray(history) && history.length > 0) {
  historyContext = '\n\n--- Conversation history ---\n' + 
    history.map(m => (m.role === 'user' ? 'User' : 'Assistant') + ': ' + m.content).join('\n\n') +
    '\n--- End of history ---';
}

// CRUCIAL : On renvoie le JSON ET on conserve les données binaires entrantes
return [{ 
  json: { sessionId, prompt, historyContext, history },
  binary: $binary // Ceci "re-transmet" l'image au nœud suivant
}];

const agentOutput = $input.first().json;
const assistantText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

const ctx = $('Prepare Chat Context').first().json;
const sessionId = ctx.sessionId;
const existingHistory = ctx.history || [];
const now = new Date().toISOString();

// Fusion de l'historique
const updatedHistory = [
  ...existingHistory,
  { role: 'assistant', content: assistantText, timestamp: now }
];

const fileContent = JSON.stringify(updatedHistory, null, 2);
// CHEMIN FEDORA
const finalFile = '/home/serge/Documents/n8n/Openrouter/openrouter_chat_history/' + sessionId + '.json';

return [{
  json: {
    sessionId,
    assistantText,
    messageCount: updatedHistory.length,
    finalFile,
    fileContent
  }
}];

const item = $('Prepare Write Command').first().json;

return [{
  json: {
    action: 'chat',
    sessionId: item.sessionId,
    assistantOutput: item.assistantText,
    messageCount: item.messageCount
  }
}];

const sessionId = $('Switch').first().json.sessionId;
const stdout    = $input.first().json.stdout || '';
const success   = stdout.includes('DELETED');
const error     = success ? null : 'Fichier introuvable : ' + sessionId;
return [{ json: { action: 'deleteSession', sessionId, success, error } }];

const stdout = $input.first().json.stdout || '';
const ctx = $('Prepare Read Command').first().json; // On récupère l'ID ici par sécurité
const sessionId = ctx.sessionId;

let history = [];
let error = null;

try {
  const parsed = JSON.parse(stdout);
  // Si le JSON est enveloppé dans un objet { history: [...] }, on l'extrait
  history = Array.isArray(parsed) ? parsed : (parsed.history || [parsed]);
} catch(e) {
  error = 'Parse error : ' + e.message;
}

return [{ 
  json: { 
    action: 'loadHistory', 
    sessionId: sessionId, // Très important pour le front-end
    history: history, 
    error: error 
  } 
}];

const sessionId = $('Switch').first().json.sessionId.replace(/-/g, '_');
const baseDir = '/home/serge/Documents/n8n/Openrouter/openrouter_chat_history';
const filePath = baseDir + '/' + sessionId + '.json';
const tmpFile  = baseDir + '/tmp_read.json';

// jq tronque aux 40 derniers messages et écrit dans tmp
const command = `jq '.[-40:]' "${filePath}" > "${tmpFile}" && cat "${tmpFile}"`;

return [{ json: { sessionId, filePath, tmpFile, command } }];

const sessionId = $('Switch').first().json.sessionId.replace(/-/g, '_');
const baseDir = '/home/serge/Documents/n8n/Openrouter/openrouter_chat_history';
const filePath = `${baseDir}/${sessionId}.json`;

// Commande Linux : on tente de supprimer, si ça échoue (fichier absent), on renvoie NOT_FOUND
const command = `rm -f "${filePath}" && echo DELETED || echo NOT_FOUND`;

return [{ json: { sessionId, filePath, command } }];

const fs = require('fs');
const path = require('path');
const item = $input.first().json;
const sessionId  = item.sessionId;
const finalFile  = item.finalFile;
const tmpFile = finalFile + '.tmp';
fs.writeFileSync(tmpFile, item.fileContent, { encoding: 'utf8' });
// déplacement atomique
fs.renameSync(tmpFile, finalFile);
return [{ json: { sessionId, assistantText: item.assistantText, messageCount: item.messageCount, fileWritten: true, finalFile } }];

const item = $input.first().json;

if (item.fileData && item.fileData.includes('base64,')) {
  const base64Part = item.fileData.split('base64,')[1];
  return [{
    json: item,
    binary: {
      file0: {
        data: base64Part,
        fileName: item.fileName,
        mimeType: item.fileType
      }
    }
  }];
}
return $input.all();

const item = $input.first().json;
let response = {};

switch (item.action) {
  case 'listSessions':
    response = { action: 'listSessions', sessions: item.sessions || [], count: (item.sessions || []).length };
    break;
  case 'loadHistory':
    response = { action: 'loadHistory', sessionId: item.sessionId, history: item.history || [], messageCount: (item.history || []).length, error: item.error || null };
    break;
  case 'chat':
    response = { action: 'chat', sessionId: item.sessionId, answer: item.assistantOutput, messageCount: item.messageCount };
    break;
  case 'deleteSession':
    response = { action: 'deleteSession', sessionId: item.sessionId, success: item.success, error: item.error || null };
    break;
  default:
    response = { error: 'Action inconnue : ' + item.action };
}

return [{ json: response }];
